import{_ as i,o as s,c as e,a4 as l}from"./chunks/framework.BhEBm8_q.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/Linux服务器网络排查总结.md","filePath":"docs/Linux服务器网络排查总结.md"}'),n={name:"docs/Linux服务器网络排查总结.md"};function t(r,a,h,p,d,o){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h2 id="一、本次故障复盘" tabindex="-1">一、本次故障复盘 <a class="header-anchor" href="#一、本次故障复盘" aria-label="Permalink to “一、本次故障复盘”">​</a></h2><p><strong>故障现象：</strong>Linux 插网线正常，但电脑无法连接服务器、服务器无法上网</p><p><strong>根本原因：</strong>物理网卡已识别（UP），但是<strong>没有获取到IPv4地址</strong>，DHCP未分配IP</p><p><strong>最终解决：</strong>更换网线，手动触发DHCP获取IP，联网恢复正常</p><hr><h2 id="二、linux-必记网络排查命令-自用高频" tabindex="-1">二、Linux 必记网络排查命令（自用高频） <a class="header-anchor" href="#二、linux-必记网络排查命令-自用高频" aria-label="Permalink to “二、Linux 必记网络排查命令（自用高频）”">​</a></h2><h3 id="_1-查看网卡-ip-地址" tabindex="-1">1. 查看网卡 &amp; IP 地址 <a class="header-anchor" href="#_1-查看网卡-ip-地址" aria-label="Permalink to “1. 查看网卡 &amp; IP 地址”">​</a></h3><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ip addr</span></span>
<span class="line"><span>ip a</span></span></code></pre></div><p><strong>解读重点：</strong></p><ul><li><p><strong>inet</strong> = 真实内网IP（可用于局域网连接）</p></li><li><p><strong>127.0.0.1</strong> = 本地回环，无效外网/局域网IP</p></li><li><p><strong>state UP</strong> = 网线正常、网卡已启用</p></li><li><p><strong>state DOWN / NO-CARRIER</strong> = 网线没插好/端口故障</p></li></ul><h3 id="_2-测试外网连通性" tabindex="-1">2. 测试外网连通性 <a class="header-anchor" href="#_2-测试外网连通性" aria-label="Permalink to “2. 测试外网连通性”">​</a></h3><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ping -c 4 223.5.5.5</span></span></code></pre></div><p><strong>作用：</strong>测试服务器能不能上网</p><p><strong>判读标准：</strong></p><ul><li><p><strong>0% packet loss</strong> = 网络正常</p></li><li><p>超时/不通 = 无IP、无网关、网络故障</p></li></ul><h3 id="_3-查看路由表-网关" tabindex="-1">3. 查看路由表（网关） <a class="header-anchor" href="#_3-查看路由表-网关" aria-label="Permalink to “3. 查看路由表（网关）”">​</a></h3><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ip route</span></span></code></pre></div><p><strong>核心判断：</strong></p><ul><li><p>有 <strong>default via 192.168.1.1</strong> = 网关正常，可以上网</p></li><li><p>无 default 行 = 只能内网，无法外网</p></li></ul><h3 id="_4-测试局域网网关是否通" tabindex="-1">4. 测试局域网网关是否通 <a class="header-anchor" href="#_4-测试局域网网关是否通" aria-label="Permalink to “4. 测试局域网网关是否通”">​</a></h3><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ping -c 4 192.168.1.1</span></span></code></pre></div><p>能通：服务器和路由器正常互通</p><p>不通：没IP、网线、路由器问题</p><h3 id="_5-快速查看本机真实内网ip" tabindex="-1">5. 快速查看本机真实内网IP <a class="header-anchor" href="#_5-快速查看本机真实内网ip" aria-label="Permalink to “5. 快速查看本机真实内网IP”">​</a></h3><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>hostname -I</span></span></code></pre></div><p>直接输出可连接的IP，干净无多余内容</p><hr><h2 id="三、本次核心修复命令-解决网卡无ip" tabindex="-1">三、本次核心修复命令（解决网卡无IP） <a class="header-anchor" href="#三、本次核心修复命令-解决网卡无ip" aria-label="Permalink to “三、本次核心修复命令（解决网卡无IP）”">​</a></h2><p><strong>场景：网卡UP、网线插好、但是没有IP</strong></p><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>sudo dhclient enp0s31f6</span></span></code></pre></div><p>作用：强制向路由器DHCP申请IP地址，立刻联网</p><hr><h2 id="四、常用补充排查命令-备用" tabindex="-1">四、常用补充排查命令（备用） <a class="header-anchor" href="#四、常用补充排查命令-备用" aria-label="Permalink to “四、常用补充排查命令（备用）”">​</a></h2><h4 id="_1-单独查看网卡状态" tabindex="-1">1. 单独查看网卡状态 <a class="header-anchor" href="#_1-单独查看网卡状态" aria-label="Permalink to “1. 单独查看网卡状态”">​</a></h4><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ip link show enp0s31f6</span></span></code></pre></div><h4 id="_2-查看ssh远程连接状态" tabindex="-1">2. 查看SSH远程连接状态 <a class="header-anchor" href="#_2-查看ssh远程连接状态" aria-label="Permalink to “2. 查看SSH远程连接状态”">​</a></h4><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>systemctl status ssh</span></span></code></pre></div><h4 id="_3-查看防火墙状态" tabindex="-1">3. 查看防火墙状态 <a class="header-anchor" href="#_3-查看防火墙状态" aria-label="Permalink to “3. 查看防火墙状态”">​</a></h4><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>sudo ufw status</span></span></code></pre></div><h4 id="_4-临时添加网关-上不了网急救" tabindex="-1">4. 临时添加网关（上不了网急救） <a class="header-anchor" href="#_4-临时添加网关-上不了网急救" aria-label="Permalink to “4. 临时添加网关（上不了网急救）”">​</a></h4><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>sudo ip route add default via 192.168.1.1</span></span></code></pre></div><hr><h2 id="五、问题总结-避坑经验" tabindex="-1">五、问题总结&amp;避坑经验 <a class="header-anchor" href="#五、问题总结-避坑经验" aria-label="Permalink to “五、问题总结&amp;避坑经验”">​</a></h2><ul><li><p><strong>网线插上不代表有网络</strong>：只是物理接通，必须拿到IP才能通信</p></li><li><p><strong>最常见故障</strong>：网卡UP、无IP → DHCP未分配地址</p></li><li><p><strong>排查顺序（标准流程）</strong>：</p><ul><li><p>ip a 看有没有IP</p></li><li><p>ip route 看有没有网关</p></li><li><p>ping 网关 测试局域网</p></li><li><p>ping 外网 测试上网</p></li></ul></li><li><p><strong>最优长期方案</strong>：路由器绑定MAC固定IP，以后永不变IP、永不失联</p></li></ul><hr><h2 id="六、局域网多台linux服务器互通结论" tabindex="-1">六、局域网多台Linux服务器互通结论 <a class="header-anchor" href="#六、局域网多台linux服务器互通结论" aria-label="Permalink to “六、局域网多台Linux服务器互通结论”">​</a></h2><p>多台服务器插同一个路由器、同一网段，<strong>自动互相互通</strong></p><p>可以互相：ping、ssh、传文件、部署服务，无需复杂配置</p>`,48)])])}const k=i(n,[["render",t]]);export{c as __pageData,k as default};
